def meta_binary_search(predicate, start_val=0):
    if predicate(start_val):
        return start_val

    low = start_val
    high = start_val + 1

    while not predicate(high):
        low = high
        high *= 2

    ans = high

    while low <= high:
        mid = low + (high - low) // 2
        if predicate(mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1

    return ans
